def meta_binary_search(p):
    if p(0):
        return 0

    k = 1
    while not p(k):
        k *= 2

    low = k // 2
    high = k
    ans = k

    while low <= high:
        mid = low + (high - low) // 2
        if p(mid):
            ans = mid
            high = mid - 1
        else:
            low = mid + 1

    return ans
